import React, { useEffect, useRef, useState } from 'react';
import {
  Chart as ChartJS, CategoryScale, LinearScale, TimeScale,
  Tooltip, Legend, BarElement,
} from 'chart.js';
import { Chart } from 'react-chartjs-2';
import 'chartjs-adapter-date-fns';

ChartJS.register(CategoryScale, LinearScale, TimeScale, Tooltip, Legend, BarElement);

const PERIODS = ['1W','1M','3M','6M','1Y'];

export default function CandlestickChart({ data = [], positive = true, height = 320, showVolume = true }) {
  const [period, setPeriod] = useState('1M');
  const [chartType, setChartType] = useState('candle'); // candle | line | area
  const isDark = document.documentElement.getAttribute('data-theme') === 'dark';

  const slicedData = React.useMemo(() => {
    const cuts = { '1W':7, '1M':30, '3M':90, '6M':180, '1Y':365 };
    return data.slice(-(cuts[period] || 30));
  }, [data, period]);

  const lineColor  = positive ? '#00b386' : '#e74c3c';
  const fillColor  = positive ? 'rgba(0,179,134,0.08)' : 'rgba(231,76,60,0.08)';
  const gridColor  = isDark ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)';
  const textColor  = isDark ? '#9297b0' : '#9297b0';

  // Build candlestick dataset manually as floating bars
  const labels  = slicedData.map(d => d.date);
  const opens   = slicedData.map(d => d.open);
  const closes  = slicedData.map(d => d.close);
  const highs   = slicedData.map(d => d.high);
  const lows    = slicedData.map(d => d.low);
  const volumes = slicedData.map(d => d.volume);
  const colors  = slicedData.map(d => d.close >= d.open ? '#00b386' : '#e74c3c');

  const lineDataset = {
    type: 'line',
    label: 'Price',
    data: closes,
    borderColor: lineColor,
    backgroundColor: fillColor,
    fill: chartType === 'area',
    tension: 0.3,
    pointRadius: 0,
    pointHoverRadius: 4,
    pointHoverBackgroundColor: lineColor,
    borderWidth: 2,
    yAxisID: 'y',
  };

  // Candlestick: render as floating bars (high-low) + body bars (open-close)
  const wickDataset = {
    type: 'bar',
    label: 'High-Low',
    data: slicedData.map((d, i) => ({ x: labels[i], y: [d.low, d.high] })),
    backgroundColor: colors,
    // barPercentage: 0.5,
    // categoryPercentage: 3.0,
    yAxisID: 'y',
  };
  const bodyDataset = {
    type: 'bar',
    label: 'Open-Close',
    data: slicedData.map((d, i) => ({
      x: labels[i],
      y: [Math.min(d.open, d.close), Math.max(d.open, d.close)],
    })),
    backgroundColor: colors.map(c => c + 'dd'),
    // barPercentage: 0.6,
    // categoryPercentage: 0.9,
    barThickness: 12,    
  maxBarThickness: 16,
    yAxisID: 'y',
  };
  const volumeDataset = {
    type: 'bar',
    label: 'Volume',
    data: volumes,
    backgroundColor: colors.map(c => c + '44'),
    barPercentage: 0.8,
    yAxisID: 'vol',
  };

  let datasets = [];
  if (chartType === 'candle') {
    datasets = [wickDataset, bodyDataset];
  } else {
    datasets = [lineDataset];
  }
  if (showVolume) datasets.push(volumeDataset);

  const chartData = { labels, datasets };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    interaction: { intersect: false, mode: 'index' },
    animation: { duration: 300 },
    plugins: {
      legend: { display: false },
      tooltip: {
        backgroundColor: isDark ? '#1a1e2c' : '#ffffff',
        titleColor: textColor,
        bodyColor: isDark ? '#e8ecf5' : '#1a1d2e',
        borderColor: isDark ? '#2a2f43' : '#eaecf5',
        borderWidth: 1,
        padding: 12,
        callbacks: {
          title: (ctx) => ctx[0]?.label,
          label: (ctx) => {
            if (ctx.dataset.label === 'Volume') return `  Vol: ${(ctx.parsed.y / 1e6).toFixed(2)}M`;
            if (ctx.dataset.label === 'Open-Close') {
              const d = slicedData[ctx.dataIndex];
              return d ? [
                `  O: ₹${d.open.toLocaleString('en-IN', { maximumFractionDigits: 2 })}`,
                `  H: ₹${d.high.toLocaleString('en-IN', { maximumFractionDigits: 2 })}`,
                `  L: ₹${d.low.toLocaleString('en-IN', { maximumFractionDigits: 2 })}`,
                `  C: ₹${d.close.toLocaleString('en-IN', { maximumFractionDigits: 2 })}`,
              ] : [];
            }
            if (ctx.dataset.label === 'Price') return `  ₹${ctx.parsed.y.toLocaleString('en-IN', { maximumFractionDigits: 2 })}`;
            return null;
          },
          filter: (item) => item.dataset.label !== 'High-Low',
        },
      },
    },
    scales: {
      x: {
        grid:   { color: gridColor, drawBorder: false },
        border: { display: false },
        ticks:  {
          color: textColor, font: { size: 11, family: 'JetBrains Mono' },
          maxTicksLimit: 8, maxRotation: 0,
          callback: (_, i) => {
            const d = labels[i];
            if (!d) return '';
            const dt = new Date(d);
            return dt.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' });
          },
        },
      },
      y: {
        position: 'right',
        grid:     { color: gridColor, drawBorder: false },
        border:   { display: false },
        ticks:    {
          color: textColor, font: { size: 11, family: 'JetBrains Mono' },
          callback: v => '₹' + v.toLocaleString('en-IN', { maximumFractionDigits: 0 }),
        },
      },
      ...(showVolume ? {
        vol: {
          position: 'left',
          grid:  { display: false },
          max:   Math.max(...volumes) * 5,
          border: { display: false },
          ticks: { display: false },
        },
      } : {}),
    },
  };

  return (
    <div style={{ display:'flex', flexDirection:'column', gap:0 }}>
      {/* Controls */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'14px 20px 10px' }}>
        {/* Period selector */}
        <div style={{ display:'flex', gap:4 }}>
          {PERIODS.map(p => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              style={{
                padding: '5px 12px',
                borderRadius: 'var(--radius-sm)',
                fontSize: 12, fontWeight: 600,
                cursor: 'pointer',
                fontFamily: 'var(--font)',
                background: period === p ? 'var(--brand)' : 'var(--surface-2)',
                color:      period === p ? '#fff' : 'var(--text-3)',
                border:     'none',
                transition: 'all 0.15s',
              }}
            >{p}</button>
          ))}
        </div>
        {/* Chart type */}
        <div style={{ display:'flex', gap:4 }}>
          {[
            { key:'line',   label:'Line' },
            { key:'area',   label:'Area' },
            { key:'candle', label:'Candle' },
          ].map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setChartType(key)}
              style={{
                padding: '5px 11px',
                borderRadius: 'var(--radius-sm)',
                fontSize: 11, fontWeight: 600,
                cursor: 'pointer',
                fontFamily: 'var(--font)',
                background: chartType === key ? 'var(--surface-3)' : 'transparent',
                color:      chartType === key ? 'var(--text-1)' : 'var(--text-3)',
                border:     `1px solid ${chartType === key ? 'var(--line-2)' : 'transparent'}`,
                transition: 'all 0.15s',
              }}
            >{label}</button>
          ))}
        </div>
      </div>

      {/* Chart */}
      <div style={{ height, padding:'0 16px 16px' }}>
        <Chart type="bar" data={chartData} options={options} />
      </div>
    </div>
  );
}
